"""
MKT Original Commentary — Job chapters 36–38
Run: python3 scripts/zc-original-job-36-38.py
Verses: ch36×33 + ch37×24 + ch38×41 (minus v38:4 already present) = 97 new entries

Key decisions in this range:
- ch36-37: Elihu's final speech — pedagogical theology of suffering; transition to storm
- ch38: YHWH's first speech from the whirlwind — rhetorical questions assert incomprehensible sovereignty
- v38:4 already written; merge_comm will skip it safely
- Divine name: YHWH (LORD) used here for the first time in the dialogue — ch38:1 marks the shift
- Constellations: Kîmāh = Pleiades, Kᵉsîl = Orion, Māzārôt uncertain (zodiac? Pleiades?)
- God's speeches use question-without-answer as the rhetorical form — note the grammar
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB = {
  "36": {
    "1": "<p><em>wayyōsep̄ ʾĕlîhûʾ wayyōʾmar</em>: 'Elihu continued and said.' <em>Yāsap̄</em> (to add, continue) — Elihu resumes without being challenged or invited. His four-speech sequence (chs. 32-37) is structurally distinct from the three-friend dialogues: Elihu is never condemned by YHWH (42:7 explicitly names only Eliphaz, Bildad, and Zophar), and his speeches transition into the divine speech from the whirlwind. Whether Elihu's theology is vindicated, silently ignored, or simply incomplete is one of the book's interpretive cruxes.</p>",
    "2": "<p><em>kattēr-lî zeʿēr waʾahawwêḵā kî ʿôḏ lᵉʾĕlôah millîm</em>: 'Bear with me a little longer and I will show you, for I still have words to speak for God.' <em>Kattēr</em> (wait a little, endure a moment — possibly from a root meaning 'wait') is a hapax. <em>Millîm lᵉʾĕlôah</em>: 'words for God' — Elihu positions himself as God's defense counsel. The claim to speak on God's behalf is significant: it's the same role Eliphaz, Bildad, and Zophar claimed, but YHWH eventually rejects their speech as wrong (42:7). Elihu's claim is not refuted, but neither is it explicitly affirmed.</p>",
    "3": "<p><em>ʾeśśāʾ ḏaʿtî lᵉmērāḥôq ûlᵉpōʿălî ʾetēn-ṣeḏeq</em>: 'I will draw my knowledge from a wide range and ascribe righteousness to my Maker.' <em>Lᵉmērāḥôq</em> (from a distance, from afar) — Elihu draws on broad knowledge, not just immediate experience. The phrase anticipates YHWH's own speech in ch. 38-41, where God surveys cosmic and natural phenomena from the widest possible vantage point. <em>Ṣeḏeq</em> (righteousness, justice) — Elihu's purpose is theodicy: to vindicate God's ways.</p>",
    "4": "<p><em>kî-ʾāmnām lōʾ-šeqer millāy ûtᵉmîm ḏēʿôt ʿimmāḵ</em>: 'For truly my words are not false; one complete in knowledge stands before you.' Elihu's self-description as <em>tᵉmîm ḏēʿôt</em> (complete/perfect in knowledge) is striking — the same adjective used of Job in 1:1 (<em>tām</em> = blameless, complete). Whether this is overconfidence or genuine claim depends on how YHWH's subsequent silence about Elihu is read. The claim of complete knowledge is exactly what the divine speech will implicitly deny to all humans — including Elihu.</p>",
    "5": "<p><em>hēn-ʾēl kabbîr wᵉlōʾ yimʾās kabbîr kōaḥ lēḇ</em>: 'Behold, God is mighty and despises no one; he is mighty in strength of understanding.' <em>Kabbîr</em> (mighty, powerful — used of God's arm in Isa 17:12 and his voice in Job 37:23) occurs twice, framing God's power as both cosmic and relational. The key claim: God's might does not produce contempt (<em>mā ʾas</em> = to reject, despise) — an implicit rebuttal of Job's charge that God treats him with sovereign disregard. <em>Kōaḥ lēḇ</em>: 'strength of heart/mind' — divine power joined with divine intelligence and compassion.</p>",
    "6": "<p><em>lōʾ yeḥayyeh rāšāʿ ûmišpāṭ ʿăniyyîm yittēn</em>: 'He does not keep the wicked alive, but gives justice to the poor.' The retribution principle stated positively: God's power works against the wicked and for the vulnerable. <em>ʿĀnî</em> (poor, humble, afflicted) — the classic prophetic concern for the oppressed (Amos 2:7; 5:12; Isa 61:1). Elihu is presenting a theodicy that takes the poor's justice seriously while maintaining divine sovereignty. The claim here is essentially the same as Eliphaz's (22:6-9), but Elihu arrives at it differently.</p>",
    "7": "<p><em>lōʾ-yiḡraʿ miṣṣaddîq ʿênāyw wᵉʾet-mᵉlāḵîm lakkisseʾ wayyôšiḇēm lānetsaḥ wayyiḡbāhû</em>: 'He does not take his eyes off the righteous; he seats them on the throne with kings and exalts them forever.' <em>Gāraʿ</em> (to diminish, take away) — God does not diminish his gaze from the righteous. The elevated-to-king imagery (<em>kissēʾ</em> = throne) has a messianic resonance: the vindicated righteous person is ultimately seated on a royal throne. The language anticipates Job's own eventual restoration (42:12-16) and the larger biblical pattern of the humiliated righteous exalted (Ps 113:7-8; 1 Sam 2:8; Luke 1:52).</p>",
    "8": "<p><em>wᵉʾim ʾăsûrîm bazziqîm yillāḵᵉdûn bᵉḥeḇlê ʿōnî</em>: 'And if they are bound in chains, caught in ropes of affliction.' The condition: if the righteous suffer (<em>ʾăsûrîm bazziqîm</em> = bound in chains, a prisoner's vocabulary). <em>Ziqqîm</em> (chains, fetters — rare; cf. Ps 149:8; Nah 3:10) and <em>ḥeḇlê ʿōnî</em> (cords of affliction) describe physical and experiential suffering as a condition that may befall even the righteous. This is Elihu's key distinction from the three friends: for Elihu, suffering can be pedagogical rather than purely punitive — the question is how the sufferer responds to it.</p>",
    "9": "<p><em>wayyaggēḏ lāhem pāʿolām ûp̄išʿêhem kî yiṯgabbārû</em>: 'Then he shows them what they have done, their transgressions — that they have acted arrogantly.' <em>Gābar</em> (to be strong, to act arrogantly, to prevail) — the arrogance (<em>yiṯgabbārû</em>, hithpael = to make oneself great, to act presumptuously) is what suffering reveals and addresses. God uses affliction as a diagnostic revelation: the suffering exposes the self-sufficiency and pride that the sufferer may not otherwise acknowledge. This is Elihu's theodicy: God speaks through suffering to bring the proud to clarity about their actual condition.</p>",
    "10": "<p><em>wayyiḡl ʾāznam lammûsār wayyōʾmar kî-yāšuḇû mēʾāwen</em>: 'He opens their ears to correction and commands that they turn from evil.' <em>Gālāh ʾōzen</em> (to open/uncover the ear) is the technical idiom for intimate disclosure — used of prophetic revelation (1 Sam 9:15; 2 Sam 7:27; Isa 22:14) and here for the insight that suffering produces. <em>Mûsār</em> (correction, discipline, instruction — the central Proverbs term) is what the suffering conveys. The ear-opening through suffering is exactly what Job needs: not to hear more arguments from the friends, but to receive divine revelation that opens his understanding.</p>",
    "11": "<p><em>ʾim-yišmᵉʿû wayyaʿōḇōḏû yᵉḵallû yᵉmêhem baṭṭôḇ ûšᵉnôṯêhem bannᵉʿîmîm</em>: 'If they listen and serve him, they will complete their days in prosperity and their years in pleasantness.' The conditional blessing: <em>šāmaʿ</em> (hear/obey — the covenantal Shema verb) + <em>ʿāḇad</em> (to serve) leads to <em>ṭôḇ</em> (goodness, prosperity) and <em>nᵉʿîm</em> (pleasantness, delight — cf. Ps 16:11; 133:1). This is the Deuteronomic covenant blessing structure (Deut 28:1-14) applied individually. The promise is not false; the problem the book has demonstrated is that it cannot be reversed: prosperity does not prove obedience, nor does suffering prove sin.</p>",
    "12": "<p><em>wᵉʾim-lōʾ yišmᵉʿû bašelaḥ yaʿāḇōrû ûyiḡwᵉʿû bilᵉʾî-ḏāʿat</em>: 'But if they do not listen, they will perish by the sword and die without ever understanding.' <em>Bilᵉʾî ḏāʿat</em> (without knowledge) — the worst outcome is not suffering but dying without ever understanding what the suffering was meant to teach. This death-without-insight is the opposite of the wisdom-goal that Proverbs sets: to die in full knowledge of God's ways. Elihu frames the stakes of Job's response: will he receive the instruction, or die incomprehendingly?</p>",
    "13": "<p><em>wᵉḥanpê lēḇ yāśîmû ʾāp̄ lōʾ-yᵉšawwᵉʿû kî ʾăsārām</em>: 'The godless in heart store up anger; they do not cry to God when he binds them.' <em>Ḥānēp̄</em> (godless, profane, polluted — used of one who has defiled the covenant, Isa 33:14; Jer 3:9) describes not atheism but practical denial of God's authority. <em>Yāśîm ʾāp̄</em> (to store up/place anger) — resentment accumulating rather than being resolved in prayer. The contrast: the godless respond to divine binding with stored anger rather than with the prayer that would open them to instruction (<em>lōʾ yᵉšawwᵉʿû</em> = they do not cry out for help).</p>",
    "14": "<p><em>tāmōt bannōʿar nap̄šām wᵉḥayyāṯām baqqᵉḏēšîm</em>: 'They die in youth, and their life ends among the cult prostitutes.' <em>Qāḏēš</em> (male cult prostitute, one devoted to a deity's sexual rites) — a reference to the Canaanite fertility cult practices condemned throughout the OT (Deut 23:17-18; 1 Kgs 14:24; 15:12; 22:46). Dying in youth and dying in the company of the cult prostitute are both signs of the dishonorable end: cut short, in a defiled context. The verse provides an ANE social illustration of how the path of refusing divine instruction terminates.</p>",
    "15": "<p><em>yaḥallēṣ ʿānî bᵉʿōnyô wᵉyiḡal balaḥaṣ ʾāznām</em>: 'But he rescues the afflicted person through their suffering and opens their ears through oppression.' The paradox that is Elihu's central contribution: the rescue comes <em>through</em> the suffering (<em>bᵉʿōnyô</em>), not from outside it. <em>Yiḡal</em> (to open wide, uncover — from <em>gālāh</em>) through <em>laḥaṣ</em> (oppression, pressure) — the very pressure that the afflicted experience is the instrument of revelation. The ear-opening through pressure is the inverse of the hardening of the heart through prosperity; Elihu's theodicy makes affliction productive rather than punitive.</p>",
    "16": "<p><em>wᵉʾap̄ hᵉsîtᵉḵā mippî ṣar raḥāḇ lōʾ-mûṣāq taḥtêhā ûnaḥat šulḥānᵉḵā mālaʾ dāšen</em>: 'Indeed, he was drawing you from the jaws of distress into a broad place, free from pressure, where your table would be spread with rich food.' Elihu applies the general principle to Job directly. <em>Raḥāḇ</em> (broad, spacious — the opposite of <em>ṣar</em> = narrow, confined) is the image of liberty and salvation (Ps 4:1; 18:19; 31:8). The promise of a full table (<em>šulḥān mālaʾ dāšen</em> = table full of fat/abundance) uses the hospitality image of Ps 23:5. Elihu sees Job's restoration as already initiated — God was in the process of deliverance before Job became impatient.</p>",
    "17": "<p><em>wᵉdîn rāšāʿ mālaʾtā dîn ûmišpāṭ yitmōḵū</em>: 'But now you are full of the judgment due the wicked; judgment and justice have seized you.' Elihu's diagnosis of Job's current condition: he is experiencing the <em>dîn rāšāʿ</em> (judgment of the wicked) — not because he is wicked, but because his response to suffering has become the response of the godless (v.13). His accumulation of resentment and his legal challenge to God have moved him into the category of the wrongfully responding sufferer. This is a more nuanced charge than the friends' direct accusation of sin.</p>",
    "18": "<p><em>kî-ḥēmāh pᵉn-yᵉsîtᵉḵā ḇᵉśāpeq wᵉraḇ-kōp̄er ʾal-yaṭṭeḵā</em>: 'Beware that anger does not lead you into scoffing; do not let the greatness of the required payment turn you away.' <em>Ḥēmāh</em> (wrath, rage) — the hot anger Job has expressed toward God. <em>Śāpeq</em> (scoffing, striking the hand, mockery) — the action of contemptuous rejection. <em>Kōp̄er</em> (ransom, expiation price, cover-price) — a technical legal term for the payment that resolves a legal dispute. Elihu warns that Job's rage may lead him to reject the divinely offered resolution of his case through scoffing pride.</p>",
    "19": "<p><em>hᵉyaʿᵃrōḵ šûʿāṯᵉḵā lōʾ bᵉṣar wᵉḵōl maʿămaddê-kōaḥ</em>: 'Will your wealth hold you in distress, or all the forces of your strength?' The rhetorical question challenges Job's reliance on former resources. <em>Šûʿāh</em> (cry for help, distress) and <em>maʿămaddê kōaḥ</em> (resources of strength, what one can lean on) — even if Job marshaled all his former wealth and social power, these cannot resolve his case before God. The question strips away the human resources that might substitute for divine resolution.</p>",
    "20": "<p><em>ʾal-tišʾap̄ hallāylāh laʿălôt ʿammîm taḥtām</em>: 'Do not long for the night, when peoples vanish from where they stand.' <em>Šāʾap̄ hallāylāh</em> (to pant/long for the night) — Job has expressed a longing for darkness and death (3:3-10; 7:4; 10:18-22). Elihu warns against this: the night in which peoples 'go up' (<em>ʿālāh</em>) from their place — i.e., the darkness of death — is not the resolution Job should seek. The warning is that seeking escape through death forecloses the possibility of resolution through response to divine instruction.</p>",
    "21": "<p><em>hišāmer ʾal-tēpen ʾel-ʾāwen kî-ʿal-zeh bāḥartā mēʿōnî</em>: 'Be careful not to turn toward evil, for this is what you have been choosing over enduring affliction.' <em>Bāḥar</em> (to choose, elect — the covenantal election verb) — Elihu frames Job's response pattern as a choice: he has been choosing <em>ʾāwen</em> (evil, iniquity, nothingness) over <em>ʿōnî</em> (affliction, poverty). The word <em>ʿōnî</em> here means not just pain but the productive suffering through which God teaches (v.15). Job has chosen to fight his suffering rather than receive its instruction.</p>",
    "22": "<p><em>hēn ʾēl yāśgîḇ bᵉkōḥô mî kāmōhû môreh</em>: 'Behold, God is exalted in his power; who is a teacher like him?' <em>Śāgaḇ</em> (to be exalted, inaccessibly high) — God's transcendence is not mere distance but the height that makes him the supreme teacher. <em>Môreh</em> (teacher, one who instructs) — a title used of human teachers (Isa 30:20) and here of God himself. The question <em>mî kāmōhû</em> (who is like him?) is the standard doxological rhetorical question (Exod 15:11; Mic 7:18; Ps 35:10). Elihu transitions from theodicy argument to praise: the God who uses suffering is the incomparable teacher.</p>",
    "23": "<p><em>mî-p̄āqaḏ ʿālāyw darkô ûmî-ʾāmar pāʿaltā ʿawlāh</em>: 'Who has prescribed his path for him? Who can say to him, &#8220;You have done wrong&#8221;?' <em>Pāqaḏ ʿāl darkô</em> (to appoint/prescribe his path for him) — the verb of divine appointment used for human oversight of God. The question anticipates YHWH's own challenge to Job in 38:2-3: who dares to question God? Elihu frames the human inability to audit God's actions — the transition to the whirlwind speech is logical: no human can prescribe God's path, and YHWH's questions will demonstrate precisely this.</p>",
    "24": "<p><em>zᵉḵōr kî-taśgîʾā p̄āʿolô ʾăšer šōrᵉrû ʾănāšîm</em>: 'Remember to extol his work, which people have celebrated in song.' <em>Śāgāʾ</em> (to magnify, make great) — extolling God's works is the antidote to the resentment that leads to rejecting divine instruction (v.13). The appeal to what humanity has sung (<em>šārar</em> = to sing, here in piel participle) about God's works is an appeal to the worshipping tradition: the psalms, hymns, and songs of Israel that celebrate divine action in creation and history. Job should situate himself within this tradition rather than positioning himself against it.</p>",
    "25": "<p><em>kāl-ʾāḏām ḥāzû-ḇô ʾĕnôš yabbîṭ mērāḥôq</em>: 'All people have seen it; everyone looks at it from a distance.' The universality of natural revelation: all humanity can observe God's works in creation (<em>ḥāzāh</em> = to see, gaze upon — also used for prophetic vision). The looking from a distance (<em>mērāḥôq</em>) does not mean ignorance but appropriate creaturely distance before the inaccessible Creator. No human can stand close enough to fully comprehend; all humanity is in the position of observer-from-afar relative to God's cosmic operations.</p>",
    "26": "<p><em>hēn-ʾēl śāggîʾ wᵉlōʾ nēḏāʿ mispar šānāyw wᵉlōʾ ḥēqer</em>: 'Behold, God is great, beyond our knowing; the number of his years cannot be counted.' <em>Śāggîʾ</em> (great, surpassingly great — an Aramaic-influenced form) — God's greatness is not merely quantitative but qualitatively beyond human comprehension. The un-numberable years (<em>mispar šānāyw wᵉlōʾ ḥēqer</em> = his years cannot be searched out) point to God's eternity: he antedates the world he created. This inaccessibility to counting and investigation is the foundation for the rhetorical questions of ch. 38-41.</p>",
    "27": "<p><em>kî yiḡraʿ niṭpê-māyim yāzōqû māṭār lᵉʾēḏô</em>: 'For he draws up drops of water; they distill as rain from the mist.' Elihu begins the meteorological section (vv.27-33) that leads into the whirlwind speech. <em>Gāraʿ niṭpê māyim</em> (he draws up/diminishes drops of water) — the water cycle: evaporation is God's work. <em>Zāqaq</em> (to refine, distill, filter) — the rain is presented as a purification process, water drawn from the depths and refined through the atmosphere. The science is observational and accurate; the theological claim is that this natural process is God's continuous activity.</p>",
    "28": "<p><em>ʾăšer-yizzᵉlû šᵉḥāqîm ṭāp̄û ʿălê ʾāḏām rāḇ</em>: 'Which the clouds pour down and drop on people in abundance.' <em>Šᵉḥāqîm</em> (clouds, thin clouds, sky-dust) — the upper atmosphere as the medium through which rain is delivered. <em>Rāḇ</em> (abundance, in great quantity) — the rain as extravagant divine provision, not merely adequate moisture but abundance. The movement from cosmic water-drawing (v.27) to abundant rainfall on humanity (v.28) describes God's care: what he draws from the depths he pours out for human benefit.</p>",
    "29": "<p><em>ʾap̄ ʾim-yāḇîn miprᵉśê ʿāḇ taršûʾôt sukkātô</em>: 'Can anyone understand the spreading of the clouds or the thunder from his canopy?' <em>Miprᵉśê ʿāḇ</em> (spreading of thick clouds) — the extension of storm clouds across the sky. <em>Taršûʾôt sukkātô</em>: 'the thunderings of his pavilion/canopy' — God's dwelling is a storm canopy from which thunder (<em>taršûʾāh</em> = crash, clatter — hapax) rolls. The question (<em>ʾim-yāḇîn</em> = can anyone understand?) introduces the epistemological challenge: human observation of weather cannot penetrate to the divine agency behind it.</p>",
    "30": "<p><em>hēn pāraś ʿālāyw ʾôrô wayyᵉšōreš rāʾšê hayyām</em>: 'See, he scatters his lightning around him and covers the roots of the sea.' <em>Pāraś ʾôrô</em> (he spreads his light/lightning) — the lightning is God's self-illumination broadcast around him. <em>Yᵉšōreš rāʾšê hayyām</em>: 'covers the roots of the sea' — the deepest foundations of the ocean are covered by divine illumination. The lightning reaching to the sea's depths is a statement about the vertical extent of God's presence: from the storm above to the ocean floor below, he is present and active.</p>",
    "31": "<p><em>kî-bām yāḏîn ʿammîm yitten-ʾōḵel lᵉmakbîr</em>: 'For by these he governs peoples and provides food in abundance.' <em>Yāḏîn ʿammîm</em> (he judges/governs peoples) — the same storm phenomena that demonstrate God's cosmic power are the instruments of his historical governance of nations. <em>Yitten ʾōḵel lᵉmakbîr</em>: 'he gives food in abundance' — rain (vv.27-28) becomes food provision (cf. Matt 5:45: he sends rain on the just and unjust). The storm is simultaneously judicial and nourishing — God's dual use of natural phenomena.</p>",
    "32": "<p><em>ʿal-kappāyim kissāh ʾôr wayyᵉṣaw ʿālêhā bᵉmaprîaʿ</em>: 'He covers his hands with the lightning and commands it to strike its mark.' The anthropomorphic image: God holds lightning in his hands (<em>kappāyim</em> = palms) and then releases it with a command. <em>Maprîaʿ</em> (that which strikes, the one who intercedes/encounters — disputed; possibly from <em>pāgaʿ</em> = to strike or meet) — the lightning is not random but directed: it hits its appointed mark. The divine volition behind each lightning strike is the theological claim.</p>",
    "33": "<p><em>yaggîḏ ʿālāyw rēʿô miqqᵉneh ʾap̄ ʿal-ʿôleh</em>: 'Its thunder announces his presence; the cattle also sense the approaching storm.' <em>Rēʿô</em> (his companion/friend — or 'his thunder' depending on the vowel pointing; most read this as 'thunder' from <em>rāʿam</em>) — the thunder is God's herald, announcing his approach. <em>Miqqᵉneh ʾap̄</em> (the cattle also — from <em>qānāh</em> = livestock) — even animals perceive the approach of the storm before humans do. The animals' instinctive sensing of divine weather activity is a subtle claim: creation is more responsive to its Creator than the humans who argue about him.</p>"
  },
  "37": {
    "1": "<p><em>ʾap̄-zōʾt yirʾaḏ libbî wayyiṭṭar mimmᵉqômô</em>: 'At this my heart trembles and leaps from its place.' Elihu describes a physical-emotional response to the approaching storm he has been describing (36:27-33). <em>Rāʿaḏ</em> (to tremble, quake) — the same verb used for the trembling of the earth at divine presence (Ps 18:7; 77:18; Isa 5:25). <em>Yiṭṭar mimmᵉqômô</em> (leaps from its place) — the heart literally 'moves from its place' in fright. Elihu's physical response establishes the appropriate creaturely posture before divine power: awe and physical fear, not calm analysis. This sets the tone for the whirlwind speech to follow.</p>",
    "2": "<p><em>šimᵉʿû šāmôaʿ bᵉrōgez qōlô wᵉhegeh mippîw yēṣēʾ</em>: 'Listen carefully to the roar of his voice and the rumble that goes out from his mouth.' <em>Šāmôaʿ šāmaʿ</em> (listen, truly listen — infinitive absolute for emphasis) — the same emphatic hearing-command as in Deut 6:4 (Shema). <em>Rōgez</em> (trembling, noise, commotion) — God's voice as the rumble of thunder. The identification of thunder with the divine voice is consistent in the OT: Ps 18:13-14; 29:3-9 (where the divine voice appears seven times in thunder). The invitation to listen to the storm is an invitation to hear God speak through the natural world.</p>",
    "3": "<p><em>taḥat kāl-haššāmayim yišrēhû wᵉʾôrô ʿal-kanpôṯ hāʾāreṣ</em>: 'He sends it out under the whole sky, and his lightning to the ends of the earth.' The spatial comprehensiveness of the storm: <em>taḥat kāl-haššāmayim</em> (under the entire sky) and <em>ʾal-kanpôṯ hāʾāreṣ</em> (to the wings/edges of the earth). The four extremities (<em>kānāp̄</em> = wing, edge) of the earth receive the divine lightning — there is no part of the created world outside the storm's reach. The cosmic scale of the storm both humbles the listener and communicates the universality of divine sovereignty.</p>",
    "4": "<p><em>ʾaḥărāyw yišʾag-qôl yārʿēm bᵉqôl gᵉʾônô wᵉlōʾ yᵉʿaqqᵉḇēm kî-yiššāmaʿ qôlô</em>: 'After the lightning a voice roars; he thunders in his majestic voice and does not hold the lightnings back once his voice is heard.' <em>Yārʿēm bᵉqôl gᵉʾônô</em>: 'he thunders in the voice of his majesty' (<em>gāʾôn</em> = majesty, pride, exaltation — used of God's majesty, Exod 15:7; Isa 2:10). The lightning precedes the thunder as God's self-announcement: the visible act comes first, then the audible proclamation. The phrase <em>wᵉlōʾ yᵉʿaqqᵉḇēm</em> (he does not hold them/restrain them) — once God speaks, the forces he has released cannot be recalled.</p>",
    "5": "<p><em>yarʿēm ʾēl bᵉqôlô niplāʾôt ʿōśeh gᵉḏōlôṯ wᵉlōʾ nēḏāʿ</em>: 'God thunders astoundingly with his voice; he does great things beyond our understanding.' <em>Niplāʾôt</em> (wonders, things too wonderful, things beyond normal capacity) — the same word used for God's deeds in the Exodus (Exod 3:20; 34:10) and creation (Ps 139:14). <em>Wᵉlōʾ nēḏāʿ</em> (and we do not know) — the epistemological limit: God's great acts exceed human comprehension even when observed. This is the refrain of the divine speech to follow: you cannot understand what you have not experienced.</p>",
    "6": "<p><em>kî lašeleg yōʾmar hᵉwē-ʾāreṣ wᵉgeśem māṭār ûgeśem miṭrôṯ ʿuzzô</em>: 'For he says to the snow, &#8220;Fall upon the earth,&#8221; and to the gentle rain and to the great downpour of his might.' God speaks to the snow and rain — natural phenomena receive divine commands. The three precipitation types: <em>šeleg</em> (snow), <em>geśem māṭār</em> (rain-shower), and <em>geśem miṭrôṯ ʿuzzô</em> (downpour of his might — heavy rain). The divine word creates and commands the natural world, not just human history: the same <em>dāḇar</em> theology of Genesis 1 applies to the ongoing governance of weather.</p>",
    "7": "<p><em>bᵉyaḏ kāl-ʾāḏām yaḥtôm lāḏaʿat kāl-ʾanšê maʿăśēhû</em>: 'He seals the hand of every person so that all humanity may know his work.' <em>Ḥāṯam bᵉyad</em> (to seal in the hand) — the storm forces human beings to stop their outdoor activity and remain inside (hands are sealed/stopped from working). The theological purpose: this forced cessation allows all humanity to perceive (<em>lāḏaʿat</em> = to know, recognize) God's work. Storm-compelled rest becomes an occasion for divine knowledge — a pattern that recurs in Israel's sabbath theology.</p>",
    "8": "<p><em>wayyābōʾ ḥayyāh beʾārāḇ ûḇimᵉʿônōṯêhā ṯiškôn</em>: 'Then the wild animals go into their dens and stay in their lairs.' The animal response to storm: the wild animals (<em>ḥayyāh</em> = wild beast) return to their dens (<em>ʾārāḇ</em> = ambush, hiding place) and dwelling places. The animals instinctively respond to the storm as a divine signal to withdraw — they know their place relative to God's power. The implicit contrast: the animals find their proper shelter during divine activity; Job has been standing exposed in argument during his own storm of suffering.</p>",
    "9": "<p><em>min-haḥeder tāḇôʾ sûp̄āh ûmiqqimrôṯ qārāh</em>: 'From the south comes the whirlwind and from the north comes the cold.' <em>Sûp̄āh</em> (whirlwind, storm-wind) — the word used for the whirlwind from which YHWH will speak (38:1). The storm approaches from the south; the cold from <em>mezārîm</em> (north winds, scattering winds). The specific directional geography of the storm reflects the actual weather patterns of the Levant. Elihu's description is building toward the actual whirlwind of ch. 38 — the same storm system he is describing rhetorically will arrive as divine voice.</p>",
    "10": "<p><em>minnišmat ʾēl yinnāṭeh-qāraḥ ûrōḥab māyim bᵉmûṣāq</em>: 'By the breath of God ice is formed and the wide waters are frozen solid.' <em>Nišmat ʾēl</em> (the breath of God) — the same phrase used for God's life-giving breath in Gen 2:7 and Job 33:4. The divine breath that creates human life also freezes water: the same capacity to transform and constitute matter operates at all scales. <em>Māyim bᵉmûṣāq</em> (waters in a mold/cast) — the frozen water takes on a fixed form, like metal poured into a cast; the liquid becomes solid by divine breath alone.</p>",
    "11": "<p><em>ʾap̄-brî yatʿîh ʿāḇ yāp̄îṣ ʿănan ʾôrô</em>: 'He loads the clouds with moisture and scatters his lightning-cloud.' <em>Brî</em> (moisture, fatness — from <em>bārāh</em> = to eat; possibly 'laden with moisture') — the clouds become heavy with water that God has loaded into them. <em>Yāp̄îṣ ʿănan ʾôrô</em>: 'he scatters his bright cloud/lightning cloud' — the dispersal of the charged clouds that produce lightning. The loading and scattering is God's direct action on the atmosphere, not natural process independent of divine agency.</p>",
    "12": "<p><em>wᵉhûʾ mᵉsibôṯ mithappêḵ bᵉṯaḥbûlôṯāyw lᵉp̄āʿolām kōl ʾăšer yᵉṣawwêm ʿal-pᵉnê ṯēḇel ʾarṣāh</em>: 'It turns in every direction by his guidance, to accomplish whatever he commands across the face of the inhabited world.' <em>Taḥbûlôt</em> (guidance, steering, direction — from the root for a ship's rudder) — God steers the storm system with nautical precision. The storm goes wherever commanded (<em>kōl ʾăšer yᵉṣawwêm</em> = all that he commands it) across the face of the inhabited world (<em>tēḇel</em> = productive earth, the inhabited world). Divine sovereignty extends from cosmic weather patterns to specific commanded outcomes.</p>",
    "13": "<p><em>ʾim-lᵉšēḇeṭ ʾim-lᵉʾarṣô ʾim-lᵉḥeseḏ yamṣiʾēhû</em>: 'He brings it whether as discipline, for his land's sake, or as steadfast love.' The threefold purpose of divinely directed weather: <em>šēḇeṭ</em> (punishment, discipline — rod/staff of correction), <em>ʾarṣô</em> (his land — perhaps 'for the sake of the earth/land'), and <em>ḥeseḏ</em> (steadfast love, covenant loyalty). The same storm can be judgment, provision, or grace depending on God's purpose. This directly challenges any single-axis interpretation of suffering (all judgment or all grace) — divine action through natural means is multi-purposeful and cannot be read by humans with certainty.</p>",
    "14": "<p><em>haʾăzîn zōʾt ʾîyôḇ ʿămōḏ wᵉhiṯḇônēn niplᵉʾôṯ ʾēl</em>: 'Listen to this, Job; stop and reflect on the wondrous works of God.' Elihu addresses Job by name for the last time. <em>ʿĂmōḏ wᵉhiṯbônēn</em> (stand still and contemplate) — the imperative of stillness before divine wonder: cease arguing, stop, and reflect. <em>Niplᵉʾôṯ ʾēl</em> (the wonders of God) — the same vocabulary as v.5. The contemplative posture Elihu urges is exactly what the whirlwind speech will demand: stop your own speaking and receive the divine challenge. Elihu's final instruction to Job is the correct preparation for the encounter about to happen.</p>",
    "15": "<p><em>hᵉtēḏaʿ bᵉśûm ʾĕlôah ʿălêhem wᵉhôpîaʿ ʾôr ʿănānô</em>: 'Do you know how God arranged these things and caused the lightning in his cloud to flash?' The rhetorical question form now adopted by Elihu anticipates YHWH's own series of unanswerable questions in ch. 38-41. <em>Bᵉśûm ʾĕlôah ʿălêhem</em>: 'when God places them' — the arrangement of storm phenomena is God's direct activity. <em>Hôpîaʿ ʾôr ʿănānô</em>: 'the lightning flashing from his cloud' — the cloud as the storage for divine light/energy. The progression from Elihu's questions to YHWH's questions is smooth: the same epistemological challenge, now at infinitely greater authority.</p>",
    "16": "<p><em>hᵉtēḏaʿ ʿal-miplaśê ʿāḇ mimplᵉʾôṯ dēʿôṯ tamîm</em>: 'Do you understand how the clouds are balanced — the wonders of the one who is perfect in knowledge?' <em>Miplaśê ʿāḇ</em> (balancings of the clouds) — the suspension of water-laden clouds in the atmosphere was a scientific mystery of the ancient world; how do the clouds hang there? <em>Dēʿôṯ tamîm</em>: 'the one who is perfect/complete in knowledge' — the epithet for God as the epistemically complete being. Compare Elihu's earlier claim (36:4) to be <em>tᵉmîm ḏēʿôt</em> (complete in knowledge) — when he uses it of God, the claim is obviously correct; when he used it of himself, it was obviously overreach.</p>",
    "17": "<p><em>ʾăšer-bᵉḡāḏêḵā ḥammîm bihaśqîṭ ʾereṣ middārôm</em>: 'Why your clothes are warm when the earth lies still under the south wind?' A more intimate observation: the warming effect of the south wind on human clothing. The question moves from cosmic (stars, seas, lightning) to bodily (your clothes feel warm). This range — from the astronomical to the personal — characterizes both Elihu's speech and YHWH's speech to follow: the Creator's knowledge encompasses the grandest and most immediate scales simultaneously.</p>",
    "18": "<p><em>tarqîaʿ ʿimmô lišᵉḥāqîm ḥăzāqîm kirʾî mûṣāq</em>: 'Have you joined him in spreading out the sky, firm and hard as a poured metal mirror?' <em>Rāqaʿ</em> (to beat out, spread, hammer thin — used for hammering metal plates in Exod 39:3 and Num 17:4) — the sky is described as hammered out, spread like beaten metal. <em>Kirʾî mûṣāq</em>: 'like a poured metal mirror' — a <em>rᵉʾî</em> (mirror) made of <em>mûṣāq</em> (poured/cast metal). Ancient mirrors were polished bronze; the sky's firmness and reflective quality (reflecting light) suggested a metallic analogy to the ancient observer. The question asks whether Job participated in the making of this sky-dome — obviously not.</p>",
    "19": "<p><em>hôḏîʿēnû mah-nōʾmar lô lōʾ-naʿărōḵ mippᵉnê-ḥōšeḵ</em>: 'Tell us what we should say to him; we cannot arrange our words because of our darkness.' Elihu concedes human limitation: <em>lōʾ naʿărōḵ mippᵉnê ḥōšeḵ</em> = 'we cannot arrange/set in order because of the darkness' — the <em>ḥōšeḵ</em> (darkness) is human ignorance. The use of the first person plural (<em>nōʾmar</em>, <em>naʿărōḵ</em>) includes Elihu himself in the category of the epistemically limited. This is the appropriate end of all human theodicy: we cannot arrange adequate speech to God.</p>",
    "20": "<p><em>hăyussappar lô kî ʾᵉḏabbēr ʾim-ʾāmar ʾîš kî yiḇalāʿ</em>: 'Should he be told that I want to speak? Can anyone speak to him without being consumed?' <em>Yiḇalāʿ</em> (to be swallowed up, consumed) — the danger of human speech before God. The question is the inverse of Moses at the burning bush (Exod 3:6: 'Moses hid his face, for he was afraid to look at God'). Direct speech to God without invitation or appropriate mediation risks annihilation. The question prepares for YHWH's speech in ch. 38: God speaks to Job directly, which is itself an act of grace rather than destruction.</p>",
    "21": "<p><em>wᵉʿattāh lōʾ-rāʾû ʾôr bāhîr hûʾ bašᵉḥāqîm wᵉrûaḥ ʿāḇᵃrāh watᵉṭahᵃrēm</em>: 'And now people cannot look at the bright light in the clouds; but the wind comes and sweeps them away.' The blinding brightness of the storm-lit sky exceeds human vision. <em>ʾôr bāhîr</em> (bright light) — the intensity of sunlight behind clouds, or lightning. <em>Rûaḥ ʿāḇᵃrāh</em> (the wind passes through) and sweeps the clouds away. The clearing of the sky after the storm is here the act of divine wind; the <em>rûaḥ</em> (spirit/wind) is the same word used for God's creative breath throughout Genesis. The storm clears to reveal what was hidden — a theological pattern that anticipates the clarity of the divine speech.</p>",
    "22": "<p><em>mizzāhāḇ yêṯê zāhāḇ ʿal-ʾĕlôah nôrāʾ hôḏ</em>: 'From the north comes golden brightness; God comes in fearsome majesty.' <em>Zāhāḇ</em> (gold) — the northern sky's brightness compared to gold. <em>Hôḏ nôrāʾ</em> (fearsome majesty, awesome splendor) — <em>hôḏ</em> is the royal majesty-term (Ps 96:6; 104:1; 111:3), here combined with <em>nôrāʾ</em> (awesome, fear-inspiring). The approach of God in the storm is the approach of the divine King in his full royal splendor — the appropriate response is awe, not argument.</p>",
    "23": "<p><em>šaddāy lōʾ-mᵉṣāʾnūhû śāggîʾ-ḵōaḥ ûmišpāṭ wᵉrōḇ-ṣᵉḏāqāh lōʾ yᵉʿanneh</em>: 'As for the Almighty, we cannot reach him; he is great in power, in justice, and in abundant righteousness; he does not oppress.' <em>Lōʾ mᵉṣāʾnūhû</em> (we cannot find/reach him) — the epistemological inaccessibility of God is the final word before YHWH speaks. Yet the inaccessible God is not arbitrary: <em>mišpāṭ</em> (justice) and <em>ṣᵉḏāqāh</em> (righteousness) characterize him. He does not oppress (<em>lōʾ yᵉʿanneh</em> — from <em>ʿānāh</em> = to answer/respond, here perhaps = to afflict, or 'he does not violate justice'). The God who is beyond reach is also the God of reliable justice — exactly the combination Job has struggled to reconcile.</p>",
    "24": "<p><em>lāḵēn yᵉrēʾûhû ʾănāšîm lōʾ-yirʾeh kol-ḥakᵉmê-lēḇ</em>: 'Therefore people fear him; he does not attend to those who are wise in their own eyes.' The conclusion: the appropriate human response to the inaccessible majestic God is <em>yirʾāh</em> (fear/awe — the foundational Proverbs wisdom term, Prov 1:7). <em>Lōʾ yirʾeh kol-ḥakᵉmê lēḇ</em>: 'he does not see/attend to those wise in their own hearts' — self-generated wisdom does not earn divine attention; the self-wise are invisible to God's regard. This is Elihu's last word, and it is also the theme YHWH will embody in the whirlwind: true wisdom begins in creaturely awe, not in self-assured argument.</p>"
  },
  "38": {
    "1": "<p><em>wayyaʿan YHWH ʾet-ʾîyôḇ min-haśśᵉʿārāh wayyōʾmar</em>: 'Then the LORD answered Job out of the whirlwind and said.' The divine name <em>YHWH</em> appears here for the first time in the entire dialogue (chs. 3-37), where only <em>ʾĕlôah</em> (God) and <em>šaddāy</em> (Almighty) have been used. The shift to the covenant name is significant: Job is addressed not by the remote transcendent deity but by YHWH, the God of the covenant and of personal relationship. <em>Śᵉʿārāh</em> (whirlwind, storm-wind — a theophanic term): the whirlwind is YHWH's vehicle of revelation (cf. Ezek 1:4; Zech 9:14; Nah 1:3), consistent with the storm theophany tradition of Sinai (Exod 19:16-19) and the Psalms (Ps 18:10-15).</p>",
    "2": "<p><em>mî zeh maḥšîḵ ʿēṣāh bimillîm bᵉlî-ḏāʿat</em>: 'Who is this who darkens counsel with words without knowledge?' The opening charge is forensic and rhetorical: <em>maḥšîḵ ʿēṣāh</em> (darkening counsel) — clouding what is clear, making wisdom unclear. Job's speeches, for all their emotional authenticity, have treated the divine governance as something that can be adjudicated by human speech (<em>millîm</em>) that lacks knowledge (<em>bᵉlî ḏāʿat</em>). The charge is not that Job lied but that he spoke beyond his competence. The same charge could be laid at the friends; YHWH addresses it to Job because Job is the one demanding an answer.</p>",
    "3": "<p><em>ḥăḡōr-nā kᵉḡeḇer ḥălāṣêḵā wᵉʾešʾālᵉḵā wᵉhôḏîʿēnî</em>: 'Brace yourself like a man; I will question you and you must answer me.' <em>ḥăḡōr kᵉḡeḇer</em> (gird your loins like a man, a warrior) — the command to prepare for combat, addressed to warriors before battle (1 Kgs 20:11; Jer 1:17). God does not destroy Job with his power but invites him into a contest of questions. The role reversal is complete: Job has been demanding a hearing before God; now God gives it — but as questioner, not defendant. <em>Wᵉhôḏîʿēnî</em> (and you must instruct me/make me know) — the ultimate ironic impossible demand: the creature instructing the Creator.</p>",
    "5": "<p><em>mî-śām mᵉmaddêhā kî ṯēḏāʿ ʾô mî-nāṭāh ʿālêhā qāw</em>: 'Who determined its measurements — do you know? Or who stretched the measuring line across it?' The question form (<em>mî</em> = who?) dominates the divine speech: 77 questions in chs. 38-41. Each question is a demonstration of divine knowledge that Job lacks and cannot claim. <em>Qāw</em> (measuring line, plumb line) — the architectural surveying tool used for the earth's dimensions. The earth was laid out with divine precision; Job was not present for the measurements and cannot claim knowledge of them.</p>",
    "6": "<p><em>ʿal-mah ʾadānêhā huṭbāʿû ʾô mî-yārāh ʾeḇen pinnātāh</em>: 'On what were its foundations (<em>ʾadānîm</em>) set? Or who laid its cornerstone?' <em>ʾAḏen</em> (base, socket, foundation — also used for the tabernacle's silver bases, Exod 26:19) — the foundations of the earth are its divine-architected supports. <em>ʾEḇen pinnāh</em> (cornerstone) — the capstone that locks an arch or the first stone that determines alignment. The building-metaphor for creation (foundations, measuring line, cornerstone) will be used in the NT for Christ as the cornerstone (Ps 118:22; Matt 21:42; Eph 2:20) — the divine builder of creation becomes the cornerstone of the new creation.</p>",
    "7": "<p><em>bᵉron yaḥad koḵᵉḇê bōqer wayyārîʿû kol-bᵉnê ʾĕlōhîm</em>: 'When the morning stars rang out together and all the divine beings shouted for joy?' <em>Koḵᵉḇê bōqer</em> (morning stars) and <em>bᵉnê ʾĕlōhîm</em> (sons of God, divine beings — the same term as 1:6; 2:1) — the angelic assembly that witnessed and celebrated creation. The cosmic joy at creation's completion (<em>rûaʿ</em> = shout with a ringing cry, used of battle-cries and worship, Ps 47:1; 98:4) is the inverse of the lament that pervades chs. 3-37: before there was suffering, there was rejoicing at the world's making. The question implies: were you there for that joy, Job?</p>",
    "8": "<p><em>wayyāsōḵ baḏᵉlāṯayim yām bᵉgîḥô mēreḥem yēṣēʾ</em>: 'Who shut in the sea with doors when it burst out from the womb?' The sea's origin: <em>gîḥô mēreḥem yēṣēʾ</em> (when it burst out from the womb) — the sea is born like a creature, emerging from a womb. But God immediately confines it with doors (<em>dalatāyim</em> = double doors). The contrast between the sea's violent emergence (it bursts) and God's calm architectural response (doors and bars, v.10) is the creation theology of Gen 1:9-10 dramatized: chaos is bounded by divine decree. The sea as embodiment of chaos (cf. Ps 93:3-4; Isa 27:1; Rev 21:1) is controlled from birth.</p>",
    "9": "<p><em>bᵉśûmî ʿānān lᵉḇūšô waʿărāp̄el ḥᵉtullāṯô</em>: 'When I made clouds its garment and thick darkness its swaddling cloth.' The extended birth metaphor continues: the newborn sea is clothed (<em>lᵉḇûš</em> = garment) in clouds and wrapped (<em>ḥᵉtullāh</em> = swaddling bands, the cloth used for newborns, Ezek 16:4; Luke 2:7) in <em>ʿărāp̄el</em> (thick darkness, the darkness of a storm or the Sinai theophany, Exod 20:21; Deut 4:11). God tends to the newborn sea as a parent, providing it coverings — but those coverings are also restraints. Divine care and divine boundary-setting are the same act.</p>",
    "10": "<p><em>wāʾešbōr ʿālāyw ḥuqqî wāʾāśîm bᵉrîaḥ ûḏᵉlāṯāyim</em>: 'When I fixed its boundaries and set its bars and doors.' <em>Ḥōq</em> (decree, boundary, prescribed limit) — the same word used for the Torah's commandments; the sea has its own divinely given <em>ḥōq</em>: a decree about how far it may go (cf. Prov 8:29: 'he prescribed a limit for the sea'). <em>Bᵉrîaḥ ûḏᵉlāṯāyim</em> (bar and double doors) — the cosmic lockwork that holds the sea in its place. YHWH is the locksmith of the ocean; the forces of chaos are not suppressed by their own weakness but contained by divine architecture.</p>",
    "11": "<p><em>wāʾōmar ʿaḏ-pōh tāḇôʾ wᵉlōʾ tôsîp̄ wᵉp̄ō-yāśît bᵉgaʾôn gallêḵā</em>: 'When I said, &#8220;This far you may come and no farther; here your proud waves will stop.&#8221;' The divine boundary-decree is given in direct speech — the most direct form of authority. <em>ʿAḏ-pō tāḇôʾ wᵉlōʾ tôsîp̄</em>: 'until here you will come and not add/continue' — the sea's advance is terminated by divine word. <em>Bᵉgaʾôn gallêḵā</em>: 'here the pride of your waves will be set/stopped' — the <em>gaʾôn</em> (majesty, pride) of the waves is the sea's power claiming space; God stops that claim with a word. The same divine word that stopped the primordial sea speaks to Job from the whirlwind.</p>",
    "12": "<p><em>hᵉmiyyāmêḵā ṣiwwîṯā bōqer yiddaʿᵉtāh šaḥar mᵉqōmô</em>: 'Have you ever commanded the morning since your life began, or told the dawn where to take its place?' The dawn is a standing appointment (<em>mᵉqôm</em> = place, station) that it has kept since creation. <em>Ṣiwwāh bōqer</em> (commanded the morning) — the morning receives a daily divine command to rise. <em>Šaḥar</em> (dawn, early light) — the dawn knows its place and goes there; Job does not command it. The daily recurrence of dawn is a standing demonstration of divine faithfulness and sovereignty: creation's order is not automatic but God's ongoing governance.</p>",
    "13": "<p><em>lᵉʾĕḥōz biḵanpôt hāʾāreṣ wᵉyinnāʿᵃrû rᵉšāʿîm mimmennāh</em>: 'So that it would seize the earth's edges and shake the wicked out of it.' The dawn's function: it grabs the edges of the earth (<em>ʾāḥaz biḵanpôt hāʾāreṣ</em> = grip the wings/corners of the earth) and shakes it like a garment being shaken to dislodge dirt (<em>nāʿar</em> = to shake out). The wicked (<em>rᵉšāʿîm</em>) who operate under cover of darkness are exposed and dislodged by the dawn — the daily sunrise is a daily moral event, a repeated act of divine justice that removes the dark's shelter from those who use it for evil (John 3:19-20; Eph 5:13).</p>",
    "14": "<p><em>titᵉhappēḵ kaḥōmer ḥôṯām wayyiṯyaṣᵉḇû kᵉmô lᵉḇûš</em>: 'The earth changes like clay under a seal; its features stand out like a garment.' <em>Kᵉḥōmer ḥôṯām</em> (like clay under a seal) — a signet ring pressed into clay wax to make an impression; the dawn's light impresses features on the earth's surface just as a seal impresses a pattern in clay. <em>Wayyiṯyaṣᵉḇû kᵉmô lᵉḇûš</em>: 'they (the features) stand out like a garment' — the earth's topography is revealed by light, as features of fabric are revealed when light hits it. The dawn literally creates visible reality by revealing what darkness concealed.</p>",
    "15": "<p><em>wᵉyimmānaʿ mērᵉšāʿîm ʾôrām ûzᵉrôaʿ rāmāh tiššāḇēr</em>: 'From the wicked their light is taken away, and the arm raised in violence shall be broken.' The dawn denies the wicked their darkness: <em>yimmānaʿ mērᵉšāʿîm ʾôrām</em> — their <em>light</em> is denied (paradoxically — the wicked's 'light' is the darkness in which they operate; the true light of day is their enemy). <em>Zᵉrôaʿ rāmāh tiššāḇēr</em>: 'the raised arm will be broken' — the arm of violent power, raised in the darkness, is broken by the morning. God's daily act of dawn is simultaneously the daily defeat of those who rely on darkness for their power.</p>",
    "16": "<p><em>hăḇāʾtā ʿal-niḇkê-yām ûḇᵉḥēqer tᵉhôm hiṯhallāḵtā</em>: 'Have you gone down to the springs of the sea, or walked through the depths of the abyss?' <em>Niḇkê yām</em> (springs of the sea — where fresh springs emerge from the sea floor; known phenomena in the ancient world) and <em>tᵉhôm</em> (the deep, the abyss — the primordial deep of Gen 1:2). Job has not descended to the sea floor or walked through the primordial deep. The geography of the question is vertical: YHWH's governance extends to depths Job has never visited and cannot even conceive of fully.</p>",
    "17": "<p><em>hăniḡlû lᵉḵā šaʿărê māwet wᵉšaʿărê ṣalmāwet tirʾeh</em>: 'Have the gates of death been revealed to you? Have you seen the doors of deepest darkness?' <em>Šaʿărê māwet</em> (gates of death) — the entrance to Sheol, the underworld (Ps 9:13; 107:18; Isa 38:10). <em>Ṣalmāwet</em> (deep shadow, death-shadow — possibly from <em>ṣēl</em> + <em>māwet</em> = shadow of death, though some parse it differently) — the darkness beyond death. Job has not passed through death's gates to verify their existence or structure. The question horizontally extends the previous vertical survey: above (storm, stars) and below (sea depths, death) — the full axis of created space is beyond Job's experience.</p>",
    "18": "<p><em>hiṯbônantā ʿaḏ-rōḥᵃḇê ʾāreṣ haggēḏ ʾim-yāḏaʿtā ḵullāh</em>: 'Have you comprehended the earth's full breadth? Tell me, if you know all of it.' <em>Rōḥab ʾāreṣ</em> (breadth of the earth) — the horizontal extent. The survey is now complete: depth (v.16 sea, v.17 death), breadth (v.18 earth). YHWH's questions have mapped the created world's full spatial extent — and Job has visited none of its edges. The epistemological point: you cannot speak confidently about the governance of a creation whose dimensions you cannot grasp.</p>",
    "19": "<p><em>ʾê-zeh haddereḵ yiškon-ʾôr waḥōšeḵ ʾê-zeh mᵉqômô</em>: 'Where is the way to where light lives? And where does darkness make its home?' <em>Yiškon-ʾôr</em> (where light dwells) — light is personified as a being with a dwelling place (<em>šāḵan</em> = to dwell, the word for the tabernacle's divine indwelling). The same for darkness: it has a <em>mᵉqôm</em> (place, habitation). The light and darkness that Genesis 1 describes as separated by God are here further personified as entities with cosmic addresses. Their addresses are known to God and unknown to Job.</p>",
    "20": "<p><em>kî tiqqāḥennû ʾel-gᵉḇûlô wᵉkî-ṯāḇîn nᵉṯîḇôṯ bêṯô</em>: 'Can you take it to its territory and find the paths to its dwelling?' Light and darkness have their own territories (<em>gᵉḇûl</em> = border, boundary) and dwelling-paths. The ability to escort light or darkness to their proper domains would require knowledge of their cosmic geography — knowledge that only the original creator of the light-darkness division (Gen 1:3-5) possesses. The question is another form of 'were you there?' — present at the original ordering of light and darkness.</p>",
    "21": "<p><em>yāḏaʿtā kî-ʾāz tiwwālēḏ ûmispar yāmêḵā rabbîm</em>: 'You know, of course — for you were born then, and the number of your days is very great!' The divine irony is devastating: <em>kî-ʾāz tiwwālēḏ</em> (for you were born back then!) — the sarcasm of impossible antiquity. Job was not born at creation; his days are not great enough to have witnessed the earth's founding. The irony inverts Job's complaint that his days are too short and his suffering too fresh: they are far too short to qualify him as a cosmological expert. The rhetorical irony here is the most artistically pointed moment in the divine speech.</p>",
    "22": "<p><em>hăḇāʾtā ʾel-ʾōṣᵉrôṯ šāleg wᵉʾōṣᵉrôṯ bārāḏ tirʾeh</em>: 'Have you gone into the storehouses of the snow, or seen the storehouses of the hail?' <em>ʾŌṣār</em> (storehouse, treasury) — the weather phenomena are stored in divine treasuries, like a king's armory. <em>Šāleg</em> (snow) and <em>bārāḏ</em> (hail) are kept in reserve (<em>ṣāpan</em> = to store up, hide in reserve, v.23). The storehouse image implies intentionality: God is not the passive backdrop of weather systems but maintains a stockpile from which he deploys snow and hail for specific purposes.</p>",
    "23": "<p><em>ʾăšer-ḥāśaḵtî lᵉʿet-ṣār lᵉyôm qᵉrāb ûmilḥāmāh</em>: 'Which I have kept in reserve for the time of trouble, for the day of battle and war.' The divine arsenal: snow and hail are not merely weather but weapons held in reserve for strategic moments. <em>ʿEt ṣār</em> (time of trouble/distress) and <em>yôm qᵉrāb ûmilḥāmāh</em> (day of battle and war) — God has cosmic weapons stockpiled for use in history's turning points. This was experienced literally in Israel's battles (Josh 10:11: hailstones against the Amorites; 1 Sam 7:10: thunder against the Philistines) and in eschatological judgment (Rev 8:7; 16:21).</p>",
    "24": "<p><em>ʾê-zeh haddereḵ yēḥāleq ʾôr yāp̄ēṣ qāḏîm ʿălê-ʾāreṣ</em>: 'By what path does the light divide, or the east wind scatter itself across the earth?' The east wind (<em>qāḏîm</em>) — in the Levant the east wind (<em>rûaḥ qādîm</em>) was the hot, desiccating sirocco from the desert, capable of devastating crops and intensifying heat (Exod 14:21; Jonah 4:8; Hos 13:15). Its path is unknown to meteorologists and unknown to Job; only the one who sends it knows where it will go.</p>",
    "25": "<p><em>mî-p̄illag laššeṭep̄ tᵉʿālāh ûdereḵ ḥăzîz qōlôṯ</em>: 'Who has cut a channel for the flood of waters, or a path for the thunderbolt?' <em>Pālag</em> (to divide, split, cut a channel) — irrigation canals are dug by human engineers; but who dug the channels that direct rainstorms? <em>Ḥăzîz qōlôṯ</em> (thunderbolt of the thunder-voice) — the lightning bolt also follows a path cut for it. The hydrological and electrical systems have their prescribed paths; God is the engineer who laid them out.</p>",
    "26": "<p><em>lᵉhaMṭîr ʿal-ʾereṣ lōʾ-ʾîš miḏḇār lōʾ-ʾāḏām bô</em>: 'To bring rain on a land where no person lives, on the desert with no human in it.' God waters the wilderness where no human benefits from the rain. This single verse undoes utilitarian theodicy: not all divine action is organized around human benefit or human observation. Creation is not anthropocentric; God waters deserts for reasons that have nothing to do with human prosperity or suffering. The implication for Job's case: God's governance of the universe does not have human happiness as its organizing principle.</p>",
    "27": "<p><em>lᵉhaśbîaʿ šōʾāh ûmᵉšōʾāh ûlᵉhaṣmîaḥ môṣāʾ ḏeše</em>: 'To satisfy the desolate wasteland and make tender grass spring up.' <em>Šōʾāh ûmᵉšōʾāh</em> (desolate wasteland) — the most barren landscape, where human life is impossible. God waters it to satisfy it (<em>śābaʿ</em> = to satisfy, fill to fullness) and make grass grow for no human observer. The satisfaction of the desert is an end in itself in the divine economy. Creation has intrinsic value before God independent of human use — a counter to the purely anthropocentric universe the friends assumed.</p>",
    "28": "<p><em>hăyēš-lāmāṭār ʾāḇ ʾô mî-hôlîḏ ʾeglê-ṭāl</em>: 'Does the rain have a father? Who has fathered the drops of dew?' Rain and dew are personified as requiring a father (<em>ʾāḇ</em> = father, one who generates). <em>Eglê ṭāl</em> (drops of dew) — literally 'dewdrops.' The question of paternity: who generates rain and dew? Not human action; they arise from the divine-natural interaction that YHWH alone comprehends. The extended birth/parent metaphor (sea was born, v.8-9; now rain and dew need a father) presents the whole meteorological system as a family of phenomena fathered and mothered by God.</p>",
    "29": "<p><em>mibbeṭen mî yāṣāʾ haqqāraḥ ûkp̄ōr šāmayim mî yᵉlāḏô</em>: 'From whose womb did the ice come? Who gave birth to the frost of heaven?' <em>Qāraḥ</em> (ice) and <em>kp̄ôr</em> (frost) are also personified as having a birth-womb. The birth-vocabulary for weather phenomena is theologically loaded: <em>reḥem</em> (womb) is the same word used for God's compassion (<em>raḥămîm</em> = compassion, from womb-roots). God is simultaneously the father and mother of the natural world's phenomena — the gendered metaphors are inclusive and complementary.</p>",
    "30": "<p><em>kāʾeḇen māyim yiṯḥabbeʾû ûp̄ᵉnê ṯᵉhôm yiṯlakkāḏû</em>: 'The waters harden like stone, and the surface of the deep is locked.' The freezing of water: <em>māyim... kāʾeḇen</em> (waters like stone) — water solidifying to stone-hardness in winter. <em>Ûp̄ᵉnê ṯᵉhôm yiṯlakkāḏû</em>: 'the face of the deep is caught/locked' — the primordial deep (<em>tᵉhôm</em> of Gen 1:2) is locked in ice. The same chaos-waters that had to be bounded in creation (v.8-11) are seasonally locked by cold — a recurring divine act of ordering. Who commands this? Not Job.</p>",
    "31": "<p><em>hᵉṯaqqšēr maʿădannôṯ kîmāh ʾô-mošᵉkôṯ kᵉsîl tᵉpattēaḥ</em>: 'Can you bind the chains of the Pleiades, or can you release the belt of Orion?' <em>Kîmāh</em> (Pleiades — the cluster of seven stars, visible spring through autumn) and <em>Kᵉsîl</em> (Orion — the winter constellation whose belt is three stars; also used metaphorically for the fool, <em>kᵉsîl</em> = fool). The chains (<em>maʿădannôṯ</em> = bonds, fetters) of the Pleiades and the belt (<em>mošᵉkôṯ</em> = bands, cords) of Orion are used as astronomical metaphors for constellation behavior. Can Job alter the seasonal positions of these stars? The question implies governance of the stellar calendar.</p>",
    "32": "<p><em>hătôṣîʾ mazzārôṯ bᵉʿittô wᵉʿayiš ʿal-bānêhā tanḥēm</em>: 'Can you bring out Mazzaroth in its season? Can you guide the Bear with its cubs?' <em>Mazzārôṯ</em> is uncertain — possibly the zodiac, possibly the twelve constellations of the year, or possibly Venus as the morning star. <em>ʿAyiš</em> (the Bear — Ursa Major/the Big Dipper) and its cubs (<em>bānêhā</em>) — the circumpolar constellation that never sets in the northern sky. The question asks about seasonal guidance of these constellations. The astronomical vocabulary confirms the ancient world's detailed observation of stellar positions; YHWH is the guide of the celestial calendar.</p>",
    "33": "<p><em>hāyāḏaʿtā ḥuqqôṯ šāmayim ʾim-tāśîm mišṭārô bāʾāreṣ</em>: 'Do you know the laws of heaven? Can you establish its rule over the earth?' <em>Ḥuqqôṯ šāmayim</em> (laws/statutes of heaven) — the fixed ordinances by which the heavens operate, the physical laws governing celestial bodies. <em>Mišṭārô</em> (its rule, dominion — from <em>šāṭar</em> = to write, rule) — can Job extend heaven's governance down to earth? The question is about the communication between celestial and terrestrial order. Job cannot write the laws of the stars, let alone enforce them on earth. The universe is a coherent rule-governed system whose constitution is divine.</p>",
    "34": "<p><em>hᵉṯārîm lāʿāḇ qôleḵā wᵉšip̄ʿat-māyim tᵉḵassêḵā</em>: 'Can you raise your voice to the clouds and make a flood of water come down?' The question of meteorological command: human voice cannot address clouds with any effect. <em>Tᵉḵassêḵā šip̄ʿat māyim</em> (a flood of water covers you) — the answer to the divine cloud-command is the downpour that covers the earth. Job can call to the clouds; they will not answer. Only YHWH's voice commands the precipitation systems of the earth.</p>",
    "35": "<p><em>hᵉtᵉšallaḥ bᵉrāqîm wᵉyēlēḵû wᵉyōʾmᵉrû lᵉḵā hinnēnû</em>: 'Can you send out lightning bolts on commission, and do they report back to you: &#8220;Here we are&#8221;?' The lightning as divine messengers: <em>yᵉšallaḥ</em> (to send, as a šālîaḥ = commissioned agent) — the lightning is dispatched like an ambassador and reports back (<em>hinnēnû</em> = here we are, the readiness formula used by Abraham at God's call, Gen 22:1, and Isaiah before God, Isa 6:8). The lightning obeys YHWH like a servant waiting to be sent; it does not obey Job. The image of lightning saying &#8220;here we are&#8221; is one of the divine speech's most vivid personifications.</p>",
    "36": "<p><em>mî-śāt baṭṭûḥôṯ ḥoḵmāh ʾô mî-nāṯan laśśeḵwî bînāh</em>: 'Who has placed wisdom in the hidden self (<em>ṭûḥôṯ</em>), or given understanding to the mind (<em>śeḵwî</em>)?' Both <em>ṭûḥôṯ</em> and <em>śeḵwî</em> are hapaxes — their meanings are disputed. <em>Ṭûḥôṯ</em>: possibly 'inward parts, hidden self' (from Ugaritic cognate); <em>śeḵwî</em>: possibly 'cock' (rooster), 'mind,' or 'seeing-organ.' If referring to the rooster, the question is: who gave the rooster the instinct to announce the dawn? If referring to the human mind, the question is: who endowed humans with wisdom at all? Either reading points to the divine origin of natural intelligence and discernment.</p>",
    "37": "<p><em>mî-yᵉsappēr šᵉḥāqîm bᵉḥoḵmāh ûnᵉḇlê šāmayim mî yašᵉḵîḇ</em>: 'Who has the wisdom to count the clouds? Who can tilt the water jars of heaven?' <em>Sāpar šᵉḥāqîm</em> (count the clouds) — a task no human can accomplish, either because of sheer number or because of their constant change. <em>Nᵉḇlê šāmayim</em> (water jars of heaven) — the clouds as jars (<em>nēḇel</em> = skin-jar, jug) full of water that God tilts to pour. The tilting metaphor is deliberately domestic and intimate: the master of the universe manages weather with the same intentionality as a servant serving water from a jar. Divine sovereignty operates at all scales simultaneously.</p>",
    "38": "<p><em>bᵉṣeqet ʿāp̄ār lammuṣṣāq ûrᵉḡāḇîm yiḏḇāqû</em>: 'When the dust hardens into a mass and the clods of dirt cling together?' The condition that follows the tilting of the water jars (v.37): when rain falls, dust hardens to mud and clods cling. The transformation of loose dry soil into cohesive wet earth is another ordinary observation presented as a divine act: God manages the water cycle down to its soil-level effects. The same God who counts clouds also knows what happens to the dirt when rain hits it.</p>",
    "39": "<p><em>hᵉṯaṣṣûḏ laʾaryēh ṭārep̄ wᵉḥayyat kᵉp̄îrîm tᵉmallēʾ</em>: 'Do you hunt prey for the lion and fill the hunger of its cubs?' The divine speech shifts from cosmic (stars, seas, weather) to biological (animals). God is the hunter-provider for lions — not a distant deity but an active sustainer of the carnivores. <em>Ṭārep̄</em> (prey, torn food) — God hunts prey for animals. This is the theodicy answer in miniature: God provides for the predators too, not just the meek. The universe's food chain is sustained by divine provision at every level.</p>",
    "40": "<p><em>kî yišḥû bammᵉʿônôṯ yēšᵉḇû bassukāh lᵉʾāraḇ</em>: 'When they crouch in their dens and wait in ambush in their thickets?' The lion's hunting posture: <em>šāḥāh</em> (to bow down, crouch) in its den (<em>mᵉʿônāh</em> = den, lair, dwelling of wild animals — used metaphorically for God's dwelling in Ps 26:8; 68:6). God knows the posture of each lion as it crouches in ambush. The divine knowledge extends from the stellar (v.31-33) to the predatory animal's daily hunting position. Omniscience of the particular and the cosmic simultaneously.</p>",
    "41": "<p><em>mî yāḵîn lāʿōrēḇ ṣêḏô kî-yaldāyw ʾel-ʾēl yᵉšawwēʿû yiṯʿū bᵉlî-ʾōḵel</em>: 'Who provides the raven its food when its chicks cry out to God and wander about hungry?' The raven (<em>ʿōrēḇ</em>) — the bird associated with wilderness and death in the OT (1 Kgs 17:4-6: ravens fed Elijah; Gen 8:7: the raven from the ark). Its chicks cry to God (<em>ʾel-ʾēl yᵉšawwēʿû</em>) when hungry — the raven's young are presented as petitioners before God. God hears and provides for the ravens, whose young cry out. The divine speech ends its first movement with a crying creature whose petition God meets — an implicit question to Job: if God hears the ravens, will he not hear you?</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'job')
    merge_comm(c, JOB)
    save_comm('mkt-original', 'job', c)
    total = sum(len(vs) for vs in JOB.values())
    print(f'job mkt-original: {total} entries written (ch36-38)')

if __name__ == '__main__':
    main()
